fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let dry_level = required_f32(params, "dry_level").map_err(anyhow::Error::msg)?;
    let early_level = required_f32(params, "early_level").map_err(anyhow::Error::msg)?;
    let late_level = required_f32(params, "late_level").map_err(anyhow::Error::msg)?;
    let size = required_f32(params, "size").map_err(anyhow::Error::msg)?;
    let width = required_f32(params, "width").map_err(anyhow::Error::msg)?;
    let delay = required_f32(params, "delay").map_err(anyhow::Error::msg)?;
    let diffuse = required_f32(params, "diffuse").map_err(anyhow::Error::msg)?;
    let low_cut = required_f32(params, "low_cut").map_err(anyhow::Error::msg)?;
    let low_xo = required_f32(params, "low_xo").map_err(anyhow::Error::msg)?;
    let low_mult = required_f32(params, "low_mult").map_err(anyhow::Error::msg)?;
    let high_cut = required_f32(params, "high_cut").map_err(anyhow::Error::msg)?;
    let high_xo = required_f32(params, "high_xo").map_err(anyhow::Error::msg)?;
    let high_mult = required_f32(params, "high_mult").map_err(anyhow::Error::msg)?;
    let spin = required_f32(params, "spin").map_err(anyhow::Error::msg)?;
    let wander = required_f32(params, "wander").map_err(anyhow::Error::msg)?;
    let decay = required_f32(params, "decay").map_err(anyhow::Error::msg)?;
    let early_send = required_f32(params, "early_send").map_err(anyhow::Error::msg)?;
    let modulation = required_f32(params, "modulation").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_DRY_LEVEL, dry_level),
        (PORT_CTRL_EARLY_LEVEL, early_level),
        (PORT_CTRL_LATE_LEVEL, late_level),
        (PORT_CTRL_SIZE, size),
        (PORT_CTRL_WIDTH, width),
        (PORT_CTRL_DELAY, delay),
        (PORT_CTRL_DIFFUSE, diffuse),
        (PORT_CTRL_LOW_CUT, low_cut),
        (PORT_CTRL_LOW_XO, low_xo),
        (PORT_CTRL_LOW_MULT, low_mult),
        (PORT_CTRL_HIGH_CUT, high_cut),
        (PORT_CTRL_HIGH_XO, high_xo),
        (PORT_CTRL_HIGH_MULT, high_mult),
        (PORT_CTRL_SPIN, spin),
        (PORT_CTRL_WANDER, wander),
        (PORT_CTRL_DECAY, decay),
        (PORT_CTRL_EARLY_SEND, early_send),
        (PORT_CTRL_MODULATION, modulation),
    ];

    let processor = lv2::build_stereo_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_LV2_AUDIO_IN_1, PORT_AUDIO_IN_LV2_AUDIO_IN_2], &[PORT_AUDIO_OUT_LV2_AUDIO_OUT_1, PORT_AUDIO_OUT_LV2_AUDIO_OUT_2], control_ports)?;
    let _ = layout;
    Ok(BlockProcessor::Stereo(Box::new(processor)))
}

